// ===== CONFIGURACIÓN DEL MENÚ =====
// Edita aquí tus platos: nombre, precio y categoría
const MENU = [
  { cat: 'Entrantes',  nombre: 'Croquetas de jamón',     precio: 6.50 },
  { cat: 'Entrantes',  nombre: 'Ensalada de la casa',     precio: 7.00 },
  { cat: 'Entrantes',  nombre: 'Patatas bravas',          precio: 5.50 },
  { cat: 'Principales', nombre: 'Hamburguesa completa',   precio: 11.50 },
  { cat: 'Principales', nombre: 'Pizza margarita',        precio: 9.50 },
  { cat: 'Principales', nombre: 'Pasta carbonara',        precio: 10.00 },
  { cat: 'Principales', nombre: 'Pollo al curry',         precio: 12.00 },
  { cat: 'Bebidas',    nombre: 'Agua mineral',            precio: 2.00 },
  { cat: 'Bebidas',    nombre: 'Refresco',                precio: 2.50 },
  { cat: 'Bebidas',    nombre: 'Cerveza',                 precio: 3.00 },
  { cat: 'Postres',    nombre: 'Tarta de queso',          precio: 4.50 },
  { cat: 'Postres',    nombre: 'Helado',                  precio: 3.50 }
];

// Número de mesa desde la URL (?mesa=5)
const mesa = $input.first().json.query?.mesa || '';

// Agrupar por categoría
const categorias = {};
MENU.forEach((p, i) => {
  if (!categorias[p.cat]) categorias[p.cat] = [];
  categorias[p.cat].push({ ...p, id: i });
});

let itemsHtml = '';
for (const cat in categorias) {
  itemsHtml += `<h2>${cat}</h2>`;
  categorias[cat].forEach(p => {
    itemsHtml += `
    <div class="plato">
      <div class="info">
        <span class="nombre">${p.nombre}</span>
        <span class="precio">${p.precio.toFixed(2)} €</span>
      </div>
      <div class="ctrl">
        <button onclick="cambiar(${p.id},-1)">−</button>
        <span id="cant-${p.id}" class="cant">0</span>
        <button onclick="cambiar(${p.id},1)">+</button>
      </div>
    </div>`;
  });
}

const PLATOS_JSON = JSON.stringify(MENU);

const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Carta - Mesa ${mesa || '?'}</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, system-ui, sans-serif; background: #f5f5f5; color: #222; padding: 16px; padding-bottom: 90px; }
  header { text-align: center; margin-bottom: 20px; }
  header h1 { font-size: 24px; }
  .mesa { background: #e63946; color: #fff; display: inline-block; padding: 4px 14px; border-radius: 20px; margin-top: 8px; font-weight: bold; }
  h2 { margin: 22px 0 10px; font-size: 18px; color: #e63946; border-bottom: 2px solid #eee; padding-bottom: 6px; }
  .plato { background: #fff; border-radius: 12px; padding: 14px; margin-bottom: 10px; display: flex; justify-content: space-between; align-items: center; box-shadow: 0 1px 3px rgba(0,0,0,.08); }
  .info { display: flex; flex-direction: column; }
  .nombre { font-weight: 600; font-size: 16px; }
  .precio { color: #888; font-size: 14px; margin-top: 2px; }
  .ctrl { display: flex; align-items: center; gap: 12px; }
  .ctrl button { width: 34px; height: 34px; border-radius: 50%; border: none; background: #e63946; color: #fff; font-size: 20px; font-weight: bold; cursor: pointer; }
  .cant { font-size: 17px; font-weight: bold; min-width: 20px; text-align: center; }
  .barra { position: fixed; bottom: 0; left: 0; right: 0; background: #fff; padding: 14px 16px; box-shadow: 0 -2px 10px rgba(0,0,0,.1); display: flex; justify-content: space-between; align-items: center; }
  .total { font-size: 18px; font-weight: bold; }
  .enviar { background: #2a9d8f; color: #fff; border: none; padding: 14px 28px; border-radius: 10px; font-size: 16px; font-weight: bold; cursor: pointer; }
  .enviar:disabled { background: #ccc; }
  #okmsg { position: fixed; inset: 0; background: rgba(0,0,0,.85); color: #fff; display: none; flex-direction: column; align-items: center; justify-content: center; text-align: center; padding: 20px; z-index: 99; }
  #okmsg h2 { color: #fff; border: none; font-size: 28px; }
</style>
</head>
<body>
<header>
  <h1>🍽️ Nuestra Carta</h1>
  <div class="mesa">Mesa ${mesa || '—'}</div>
</header>
${itemsHtml}
<div class="barra">
  <span class="total">Total: <span id="total">0.00</span> €</span>
  <button class="enviar" id="btn" onclick="enviar()" disabled>Pedir</button>
</div>
<div id="okmsg">
  <h2>✅ ¡Pedido enviado!</h2>
  <p style="margin-top:12px;font-size:18px">Cocina ya lo está preparando.</p>
</div>
<script>
  const MENU = ${PLATOS_JSON};
  const MESA = '${mesa}';
  const cant = {};
  function cambiar(id, d) {
    cant[id] = Math.max(0, (cant[id]||0) + d);
    document.getElementById('cant-'+id).textContent = cant[id];
    actualizar();
  }
  function actualizar() {
    let total = 0, hay = false;
    for (const id in cant) { if (cant[id] > 0) { total += MENU[id].precio * cant[id]; hay = true; } }
    document.getElementById('total').textContent = total.toFixed(2);
    document.getElementById('btn').disabled = !hay;
  }
  async function enviar() {
    const items = [];
    for (const id in cant) { if (cant[id] > 0) items.push({ nombre: MENU[id].nombre, cantidad: cant[id], precio: MENU[id].precio }); }
    document.getElementById('btn').disabled = true;
    try {
      const pedidoUrl = window.location.href.replace(/\\/menu.*/, '/pedido');
      await fetch(pedidoUrl, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ mesa: MESA, items: items })
      });
      document.getElementById('okmsg').style.display = 'flex';
    } catch(e) { alert('Error al enviar. Inténtalo otra vez.'); document.getElementById('btn').disabled = false; }
  }
</script>
</body>
</html>`;

return [{ json: { html } }];

// Guardar el pedido en el almacenamiento estático del workflow
const staticData = $getWorkflowStaticData('global');
if (!staticData.pedidos) staticData.pedidos = [];

const body = $input.first().json.body || {};
const mesa = body.mesa || '?';
const items = body.items || [];

const total = items.reduce((s, i) => s + (i.precio * i.cantidad), 0);

const pedido = {
  id: Date.now(),
  mesa: mesa,
  items: items,
  total: total,
  hora: new Date().toLocaleTimeString('es-ES', { hour: '2-digit', minute: '2-digit' }),
  estado: 'nuevo'
};

staticData.pedidos.push(pedido);

// Mantener solo los últimos 50 pedidos
if (staticData.pedidos.length > 50) {
  staticData.pedidos = staticData.pedidos.slice(-50);
}

return [{ json: { ok: true, pedido } }];

// Leer pedidos guardados
const staticData = $getWorkflowStaticData('global');
if (!staticData.pedidos) staticData.pedidos = [];
const pedidos = staticData.pedidos;

const query = $input.first().json.query || {};

// Marcar un pedido como entregado (?entregado=ID)
if (query.entregado) {
  const id = Number(query.entregado);
  const p = pedidos.find(x => x.id === id);
  if (p) p.estado = 'entregado';
  return [{ json: { _json: true, pedidos: pedidos.filter(x => x.estado !== 'entregado').reverse() } }];
}

// Endpoint para datos JSON (la pantalla lo consulta cada pocos segundos)
const esJson = query.data === '1';

if (esJson) {
  // Devolver pedidos no entregados, más recientes primero
  const activos = pedidos.filter(p => p.estado !== 'entregado').reverse();
  return [{ json: { _json: true, pedidos: activos } }];
}

// Si no, devolver la pantalla HTML
const html = `<!DOCTYPE html>
<html lang="es">
<head>
<meta charset="UTF-8">
<meta name="viewport" content="width=device-width, initial-scale=1.0">
<title>Cocina - Pedidos</title>
<style>
  * { box-sizing: border-box; margin: 0; padding: 0; }
  body { font-family: -apple-system, system-ui, sans-serif; background: #1a1a1a; color: #fff; padding: 16px; }
  header { display: flex; justify-content: space-between; align-items: center; margin-bottom: 20px; }
  header h1 { font-size: 26px; }
  .estado { font-size: 14px; color: #2a9d8f; }
  .grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr)); gap: 16px; }
  .ticket { background: #2b2b2b; border-radius: 12px; padding: 16px; border-left: 5px solid #e63946; animation: aparece .3s; }
  @keyframes aparece { from { opacity: 0; transform: scale(.95); } }
  .ticket.nuevo { border-left-color: #e63946; }
  .tk-head { display: flex; justify-content: space-between; align-items: center; margin-bottom: 12px; }
  .mesa { background: #e63946; padding: 6px 14px; border-radius: 8px; font-weight: bold; font-size: 18px; }
  .hora { color: #999; font-size: 14px; }
  .item { display: flex; justify-content: space-between; padding: 6px 0; border-bottom: 1px solid #3a3a3a; font-size: 16px; }
  .item .cant { background: #2a9d8f; color: #fff; border-radius: 6px; padding: 2px 8px; font-weight: bold; margin-right: 8px; }
  .item-nombre { flex: 1; }
  .listo { width: 100%; margin-top: 12px; background: #2a9d8f; color: #fff; border: none; padding: 12px; border-radius: 8px; font-size: 15px; font-weight: bold; cursor: pointer; }
  .vacio { text-align: center; color: #666; margin-top: 80px; font-size: 20px; }
</style>
</head>
<body>
<header>
  <h1>👨‍🍳 Pedidos en cocina</h1>
  <span class="estado" id="estado">● Conectado</span>
</header>
<div class="grid" id="grid"></div>
<div class="vacio" id="vacio">Sin pedidos pendientes</div>
<audio id="ding" src="data:audio/wav;base64,UklGRl9vT19XQVZFZm10IBAAAAABAAEAQB8AAEAfAAABAAgAZGF0YU"></audio>
<script>
  let vistos = new Set();
  let primera = true;
  async function cargar() {
    try {
      const r = await fetch('?data=1');
      const d = await r.json();
      const grid = document.getElementById('grid');
      const vacio = document.getElementById('vacio');
      document.getElementById('estado').textContent = '● Conectado';
      const pedidos = d.pedidos || [];
      // Detectar pedidos nuevos para sonar
      let nuevo = false;
      pedidos.forEach(p => { if (!vistos.has(p.id)) { vistos.add(p.id); if (!primera) nuevo = true; } });
      primera = false;
      if (nuevo) { try { document.getElementById('ding').play(); } catch(e){} }
      vacio.style.display = pedidos.length ? 'none' : 'block';
      grid.innerHTML = pedidos.map(p => {
        const items = p.items.map(i => '<div class="item"><span><span class="cant">'+i.cantidad+'</span><span class="item-nombre">'+i.nombre+'</span></span></div>').join('');
        return '<div class="ticket nuevo"><div class="tk-head"><span class="mesa">Mesa '+p.mesa+'</span><span class="hora">'+p.hora+'</span></div>'+items+'<button class="listo" onclick="marcar('+p.id+')">✓ Listo / Entregado</button></div>';
      }).join('');
    } catch(e) {
      document.getElementById('estado').textContent = '● Sin conexión';
    }
  }
  async function marcar(id) {
    try { await fetch('?entregado='+id); cargar(); } catch(e){}
  }
  cargar();
  setInterval(cargar, 4000);
</script>
</body>
</html>`;

return [{ json: { _json: false, html } }];
